class NeighborSum {
    constructor(grid) {
        this.grid = grid;
        this.n = grid.length;
        this.loc = new Map();
        for (let r = 0; r < this.n; r++) {
            for (let c = 0; c < this.n; c++) {
                this.loc.set(grid[r][c], [r, c]);
            }
        }
    }
    _sum(value, dirs) {
        const [r, c] = this.loc.get(value);
        let total = 0;
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < this.n && nc >= 0 && nc < this.n) {
                total += this.grid[nr][nc];
            }
        }
        return total;
    }
    adjacentSum(value) {
        return this._sum(value, [[-1, 0], [1, 0], [0, -1], [0, 1]]);
    }
    diagonalSum(value) {
        return this._sum(value, [[-1, -1], [-1, 1], [1, -1], [1, 1]]);
    }
}
